export enum UserRole {
  CUSTOMER = "CUSTOMER",
  SELLER = "SELLER",
  ADMIN = "ADMIN",
  SUPPORT = "SUPPORT",
}

export enum UserStatus {
  ACTIVE = "ACTIVE",
  INACTIVE = "INACTIVE",
  SUSPENDED = "SUSPENDED",
  PENDING_VERIFICATION = "PENDING_VERIFICATION",
}

export interface UserPreferences {
  locale: string;
  currency: CurrencyCode;
  marketingEmails: boolean;
  smsNotifications: boolean;
  pushNotifications: boolean;
}

export interface UserProfile {
  firstName: string;
  lastName: string;
  displayName?: string;
  avatarUrl?: string;
  phone?: string;
  dateOfBirth?: Date;
}

export interface User {
  id: string;
  email: string;
  role: UserRole;
  status: UserStatus;
  profile: UserProfile;
  preferences: UserPreferences;
  addresses: Address[];
  defaultAddressId?: string;
  favoriteProductIds: string[];
  lastLoginAt?: Date;
  emailVerifiedAt?: Date;
  createdAt: Date;
  updatedAt: Date;
}

export interface UserRequest {
  id: string;
}

export interface RegisterUserRequest {
  email: string;
  password: string;
  profile: UserProfile;
  preferences?: UserPreferences;
}

export interface LoginRequest {
  email: string;
  password: string;
}

export interface LoginResponse {
  accessToken: string;
  refreshToken: string;
  expiresAt: Date;
  user: User;
}

export interface RefreshTokenRequest {
  refreshToken: string;
}

export interface UpdateProfileRequest {
  userId: string;
  profile: UserProfile;
}

export interface ChangePasswordRequest {
  userId: string;
  currentPassword: string;
  newPassword: string;
}

export interface AddAddressRequest {
  userId: string;
  address: Address;
}

export interface UpdateAddressRequest {
  userId: string;
  addressId: string;
  address: Address;
}

export interface UserListRequest {
  pagination: PaginationRequest;
  role?: UserRole;
  status?: UserStatus;
  query?: string;
}

export interface UserListResponse {
  items: User[];
  meta: PaginationMeta;
}

export interface UserService {
  getUser(data: UserRequest): User;
  listUsers(data: UserListRequest): UserListResponse;
  createUser(data: RegisterUserRequest): User;
  updateUser(data: UpdateProfileRequest): User;
  updateUserStatus(data: UserRequest): User;
  deleteUser(data: UserRequest): EmptyResponse;
  addAddress(data: AddAddressRequest): User;
  updateAddress(data: UpdateAddressRequest): User;
  removeAddress(data: UpdateAddressRequest): User;
}

export interface AuthService {
  register(data: RegisterUserRequest): LoginResponse;
  login(data: LoginRequest): LoginResponse;
  logout(data: RefreshTokenRequest): EmptyResponse;
  refreshToken(data: RefreshTokenRequest): LoginResponse;
  changePassword(data: ChangePasswordRequest): EmptyResponse;
  verifyEmail(data: IdRequest): User;
  requestPasswordReset(data: LoginRequest): EmptyResponse;
}

